import os, json, datetime, time

print('=== CLEANUP SCAN ===')
print()

home = os.path.expanduser('~')
results = {}

# 1. Temp folder scan
temp_dir = os.path.join(home, 'AppData', 'Local', 'Temp')
temp_size = 0
temp_files = 0
temp_errors = 0
if os.path.exists(temp_dir):
    for root, dirs, files in os.walk(temp_dir):
        for f in files:
            try:
                fp = os.path.join(root, f)
                temp_size += os.path.getsize(fp)
                temp_files += 1
            except:
                temp_errors += 1
results['temp'] = {'size_mb': round(temp_size/(1024**2), 1), 'files': temp_files, 'errors': temp_errors}
print(f'[Temp] {results["temp"]["size_mb"]} MB, {temp_files} files')

# 2. .cache folder scan
cache_dir = os.path.join(home, '.cache')
cache_size = 0
cache_files = 0
if os.path.exists(cache_dir):
    for root, dirs, files in os.walk(cache_dir):
        for f in files:
            try:
                fp = os.path.join(root, f)
                cache_size += os.path.getsize(fp)
                cache_files += 1
            except:
                pass
results['cache'] = {'size_mb': round(cache_size/(1024**2), 1), 'files': cache_files}
print(f'[.cache] {results["cache"]["size_mb"]} MB, {cache_files} files')

# 3. Rustup check
rustup_dir = os.path.join(home, '.rustup')
rustup_info = {'exists': False}
if os.path.exists(rustup_dir):
    rustup_info['exists'] = True
    rust_size = 0
    latest_mod = 0
    rust_files = 0
    for root, dirs, files in os.walk(rustup_dir):
        for f in files:
            try:
                fp = os.path.join(root, f)
                rust_size += os.path.getsize(fp)
                mt = os.path.getmtime(fp)
                if mt > latest_mod:
                    latest_mod = mt
                rust_files += 1
            except:
                pass
    rustup_info['size_mb'] = round(rust_size/(1024**2), 1)
    rustup_info['files'] = rust_files
    rustup_info['last_modified'] = datetime.datetime.fromtimestamp(latest_mod).strftime('%Y-%m-%d %H:%M:%S') if latest_mod > 0 else 'unknown'
    rustup_info['days_since_last_use'] = (datetime.datetime.now() - datetime.datetime.fromtimestamp(latest_mod)).days if latest_mod > 0 else -1
    cargo_dir = os.path.join(home, '.cargo')
    if os.path.exists(cargo_dir):
        cargo_latest = 0
        cargo_size = 0
        for root, dirs, files in os.walk(cargo_dir):
            for f in files:
                try:
                    fpp = os.path.join(root, f)
                    mt = os.path.getmtime(fpp)
                    cargo_size += os.path.getsize(fpp)
                    if mt > cargo_latest:
                        cargo_latest = mt
                except:
                    pass
        rustup_info['cargo_last_modified'] = datetime.datetime.fromtimestamp(cargo_latest).strftime('%Y-%m-%d %H:%M:%S') if cargo_latest > 0 else 'unknown'
        rustup_info['cargo_days_since_use'] = (datetime.datetime.now() - datetime.datetime.fromtimestamp(cargo_latest)).days if cargo_latest > 0 else -1
        rustup_info['cargo_size_mb'] = round(cargo_size/(1024**2), 1)
    rs_files = []
    for root, dirs, files in os.walk(home):
        dirs[:] = [d for d in dirs if d not in ['.rustup', '.cargo', 'node_modules', 'AppData', '.cache', '.gemini', '.antigravity']]
        for f in files:
            if f.endswith('.rs'):
                rs_files.append(os.path.join(root, f))
        if len(rs_files) >= 5:
            break
    rustup_info['rs_files_found'] = rs_files[:5]
results['rustup'] = rustup_info
print(f'[Rustup] Exists: {rustup_info["exists"]}, Size: {rustup_info.get("size_mb", 0)} MB')
print(f'  Last modified: {rustup_info.get("last_modified", "N/A")}')
print(f'  Days since last use: {rustup_info.get("days_since_last_use", "N/A")}')
print(f'  Cargo size: {rustup_info.get("cargo_size_mb", 0)} MB')
print(f'  .rs files found: {len(rustup_info.get("rs_files_found", []))}')
if rustup_info.get('rs_files_found'):
    for rf in rustup_info['rs_files_found']:
        print(f'    {rf}')

# 4. Desktop scan
desktop_dir = os.path.join(home, 'Desktop')
desktop_items = []
if os.path.exists(desktop_dir):
    for item in os.listdir(desktop_dir):
        fp = os.path.join(desktop_dir, item)
        try:
            if os.path.isfile(fp):
                size = os.path.getsize(fp)
                ext = os.path.splitext(item)[1].lower()
                mtime = os.path.getmtime(fp)
                desktop_items.append({'name': item, 'type': 'file', 'ext': ext, 'size_mb': round(size/(1024**2), 2), 'modified': datetime.datetime.fromtimestamp(mtime).strftime('%Y-%m-%d')})
            elif os.path.isdir(fp):
                dir_size = 0
                dir_files = 0
                for root, dirs, files in os.walk(fp):
                    for f in files:
                        try:
                            dir_size += os.path.getsize(os.path.join(root, f))
                            dir_files += 1
                        except:
                            pass
                desktop_items.append({'name': item, 'type': 'folder', 'size_mb': round(dir_size/(1024**2), 2), 'file_count': dir_files})
        except:
            desktop_items.append({'name': item, 'type': 'unknown', 'size_mb': 0})
desktop_items.sort(key=lambda x: x.get('size_mb', 0), reverse=True)
results['desktop'] = desktop_items
print(f'\n[Desktop] {len(desktop_items)} items:')
for item in desktop_items[:25]:
    print(f'  {item["type"].ljust(7)} {str(item.get("size_mb",0)).rjust(8)} MB  {item["name"]}')

# 5. Downloads scan
dl_dir = os.path.join(home, 'Downloads')
dl_items = []
if os.path.exists(dl_dir):
    for item in os.listdir(dl_dir):
        fp = os.path.join(dl_dir, item)
        try:
            if os.path.isfile(fp):
                size = os.path.getsize(fp)
                ext = os.path.splitext(item)[1].lower()
                mtime = os.path.getmtime(fp)
                age_days = (datetime.datetime.now() - datetime.datetime.fromtimestamp(mtime)).days
                dl_items.append({'name': item, 'ext': ext, 'size_mb': round(size/(1024**2), 2), 'age_days': age_days})
            elif os.path.isdir(fp):
                dir_size = 0
                for root, dirs, files in os.walk(fp):
                    for f in files:
                        try:
                            dir_size += os.path.getsize(os.path.join(root, f))
                        except:
                            pass
                mtime = os.path.getmtime(fp)
                age_days = (datetime.datetime.now() - datetime.datetime.fromtimestamp(mtime)).days
                dl_items.append({'name': item, 'ext': 'folder', 'size_mb': round(dir_size/(1024**2), 2), 'age_days': age_days})
        except:
            pass
dl_items.sort(key=lambda x: x.get('size_mb', 0), reverse=True)
results['downloads'] = dl_items
print(f'\n[Downloads] {len(dl_items)} items:')
for item in dl_items[:15]:
    print(f'  {str(item.get("age_days",0)).rjust(4)}d old  {str(item.get("size_mb",0)).rjust(8)} MB  {item["name"]}')

# Save
report_dir = os.path.join(home, 'agent_reports')
os.makedirs(report_dir, exist_ok=True)
with open(os.path.join(report_dir, 'cleanup_scan.json'), 'w', encoding='utf-8') as f:
    json.dump(results, f, indent=2, ensure_ascii=False)

print(f'\nScan saved to: {os.path.join(report_dir, "cleanup_scan.json")}')
print('=== SCAN COMPLETE ===')
